```class Solution {
public:
    int countKReducibleNumbers(string s, int k) {
        int n = stoi(s, 0, 2);
        int res = 0;
        for (int i = 1; i < n; ++i) {
            int cnt = 0, x = i;
            while (x > 1) {
                cnt += __builtin_popcount(x);
                x = __builtin_popcount(x);
                if (cnt > k) break;
            }
            if (cnt <= k) res++;
        }
        return res % (1e9 + 7);
    }
};
